function transformValue(input) {
    const mapping = { 'A': 'AUTH', 'V': 'ILEV' };
    return mapping[input] || input;
}

function addressParser(input, outputField) {
    // Parse ISO20022 address format with 2/ and 3/ prefixes
    // 2/ = Address line
    // 3/ = Country + Town (if followed by 2 parts) OR Address line (if followed by 1 part)
    // Example: "2/Building 5/3/Main Street/3/GB/London"
    // Returns: Country, TownName, AddressLine1, AddressLine2 based on outputField parameter

    if (!input || typeof input !== 'string') {
        return '';
    }

    const parts = input.split('/').filter(p => p.trim() !== '');

    let country = '';
    let townName = '';
    let addressLines = [];

    // Parse all parts
    for (let i = 0; i < parts.length; i++) {
        const part = parts[i].trim();

        // 3/ prefix - check what follows
        if (part === '3' && i + 1 < parts.length) {
            // Look ahead to see if this is Country+Town or just an Address line
            const nextPart = parts[i + 1].trim();

            // Check if there's a second part after the next part
            if (i + 2 < parts.length) {
                const secondNextPart = parts[i + 2].trim();

                // If the second next part is NOT a prefix (2 or 3), this is Country+Town
                if (secondNextPart !== '2' && secondNextPart !== '3') {
                    // This is 3/Country/Town format
                    country = nextPart;
                    townName = secondNextPart;
                    i += 2; // Skip next 2 parts as they're consumed
                    continue;
                }
            }

            // If we get here, 3/ is followed by only 1 part (address line)
            addressLines.push(nextPart);
            i += 1; // Skip next part as it's consumed
        }
        // 2/ prefix indicates address line
        else if (part === '2' && i + 1 < parts.length) {
            addressLines.push(parts[i + 1].trim());
            i += 1; // Skip next part as it's consumed
        }
        // Handle case where user provides address without prefix
        else if (part !== '2' && part !== '3' && country === '' && townName === '') {
            // Before Country+Town is found, collect as address lines
            addressLines.push(part);
        }
    }

    // Return the requested field
    switch(outputField) {
        case 'country':
        case 'creditorCountry':
        case 'debtorCountry':
            return country;

        case 'town':
        case 'townName':
        case 'creditorTownName':
        case 'debtorTownName':
            return townName;

        case 'address1':
        case 'addressLine1':
        case 'creditorAddressLine1':
        case 'debtorAddressLine1':
            return addressLines[0] || '';

        case 'address2':
        case 'addressLine2':
        case 'creditorAddressLine2':
        case 'debtorAddressLine2':
            return addressLines[1] || '';

        case 'address3':
        case 'addressLine3':
        case 'creditorAddressLine3':
        case 'debtorAddressLine3':
            return addressLines[2] || '';

        default:
            // If no field specified, return full parsed object as JSON
            return JSON.stringify({
                country: country,
                townName: townName,
                addressLine1: addressLines[0] || '',
                addressLine2: addressLines[1] || '',
                addressLine3: addressLines[2] || ''
            });
    }
}

